update t_customer_loss
cus_no = #{cusNo,jdbcType=VARCHAR}, cus_name = #{cusName,jdbcType=VARCHAR}, cus_manager = #{cusManager,jdbcType=VARCHAR}, last_order_time = #{lastOrderTime,jdbcType=TIMESTAMP}, confirm_loss_time = #{confirmLossTime,jdbcType=TIMESTAMP}, state = #{state,jdbcType=INTEGER}, loss_reason = #{lossReason,jdbcType=VARCHAR}, is_valid = #{isValid,jdbcType=INTEGER}, create_date = #{createDate,jdbcType=TIMESTAMP}, update_date = #{updateDate,jdbcType=TIMESTAMP},
where id = #{id,jdbcType=INTEGER}
